import{b as n,I as a,g as s,j as t}from"./chunks/framework.DUo3J_Qe.js";const h=JSON.parse('{"title":"Réseaux de neurones convolutifs (CNN)","description":"","frontmatter":{},"headers":[],"relativePath":"fr/learning/deep-learning/cnn/introduction.md","filePath":"fr/learning/deep-learning/cnn/introduction.md"}'),o={name:"fr/learning/deep-learning/cnn/introduction.md"};function r(i,e,u,l,p,c){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="reseaux-de-neurones-convolutifs-cnn" tabindex="-1">Réseaux de neurones convolutifs (CNN) <a class="header-anchor" href="#reseaux-de-neurones-convolutifs-cnn" aria-label="Permalink to &quot;Réseaux de neurones convolutifs (CNN)&quot;">​</a></h1><p>Les CNN sont une famille de réseaux de neurones conçus pour traiter des données organisées en <strong>grille</strong> — images (2D), vidéos (3D), signaux audio (1D). Ils sont la brique de base de quasiment toutes les tâches de vision par ordinateur.</p><h2 id="pourquoi-pas-un-reseau-classique" tabindex="-1">Pourquoi pas un réseau classique ? <a class="header-anchor" href="#pourquoi-pas-un-reseau-classique" aria-label="Permalink to &quot;Pourquoi pas un réseau classique ?&quot;">​</a></h2><p>Un réseau de neurones classique (ANN) connecte chaque neurone à tous ceux de la couche suivante. Sur une image 256×256 en RGB, ça donne <strong>196 608 entrées</strong> — et chaque connexion a un poids à apprendre. C&#39;est massif, lent, et surtout inutile : un pixel n&#39;a de sens que dans le contexte de ses voisins immédiats.</p><p>Un CNN résout ce problème avec deux idées simples :</p><ul><li><strong>Localité</strong> — un filtre ne regarde qu&#39;une petite zone à la fois (ex. 3×3 pixels)</li><li><strong>Partage de poids</strong> — le même filtre est appliqué partout sur l&#39;image</li></ul><h2 id="la-convolution" tabindex="-1">La convolution <a class="header-anchor" href="#la-convolution" aria-label="Permalink to &quot;La convolution&quot;">​</a></h2><p>Un filtre (ou <em>kernel</em>) est une petite matrice de poids. On le fait glisser sur l&#39;image : à chaque position, on multiplie les valeurs du filtre par les pixels sous-jacents et on additionne. Le résultat est un pixel dans la <strong>carte d&#39;activation</strong> (<em>feature map</em>).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image 5×5          Filtre 3×3        Feature map 3×3</span></span>
<span class="line"><span>┌─────────────┐    ┌───┬───┬───┐     ┌─────────────┐</span></span>
<span class="line"><span>│ 1  2  3  0  │    │ 1 │ 0 │-1 │     │    ...      │</span></span>
<span class="line"><span>│ 4  5  6  1  │  × │ 1 │ 0 │-1 │  =  │    ...      │</span></span>
<span class="line"><span>│ 7  8  9  2  │    │ 1 │ 0 │-1 │     │    ...      │</span></span>
<span class="line"><span>│ 0  1  2  3  │    └───┴───┴───┘     └─────────────┘</span></span>
<span class="line"><span>└─────────────┘</span></span></code></pre></div><p>Ce filtre détecte les <strong>bords verticaux</strong>. D&#39;autres filtres détectent des bords horizontaux, des coins, des textures — le réseau les apprend automatiquement pendant l&#39;entraînement.</p><h2 id="architecture-typique" tabindex="-1">Architecture typique <a class="header-anchor" href="#architecture-typique" aria-label="Permalink to &quot;Architecture typique&quot;">​</a></h2><p>Un CNN est une succession de blocs, chacun réduisant la résolution spatiale tout en augmentant le nombre de filtres :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image                Conv + ReLU         Pooling          ...       Sortie</span></span>
<span class="line"><span>(256×256×3)    →    (256×256×32)    →   (128×128×32)    →  ...  →  classes</span></span></code></pre></div><p><strong>Couche de convolution</strong> — applique N filtres en parallèle → produit N feature maps.</p><p><strong>ReLU</strong> — <code>max(0, x)</code> sur chaque pixel. Supprime les valeurs négatives, introduit la non-linéarité.</p><p><strong>Pooling</strong> — réduit la résolution (ex. garder le max dans chaque fenêtre 2×2). Le réseau devient insensible aux petits décalages de position.</p><p><strong>Couche fully connected</strong> — à la fin, les feature maps sont aplaties et connectées à la sortie (classification).</p><h2 id="ce-que-le-cnn-apprend-couche-par-couche" tabindex="-1">Ce que le CNN apprend couche par couche <a class="header-anchor" href="#ce-que-le-cnn-apprend-couche-par-couche" aria-label="Permalink to &quot;Ce que le CNN apprend couche par couche&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Couche</th><th>Ce qu&#39;elle détecte</th></tr></thead><tbody><tr><td>1</td><td>Bords, gradients de couleur</td></tr><tr><td>2</td><td>Textures, motifs simples</td></tr><tr><td>3</td><td>Formes géométriques</td></tr><tr><td>Profondes</td><td>Objets complexes (couronne d&#39;arbre, fenêtre, toit…)</td></tr></tbody></table><p>Les premières couches sont génériques (détection de bords), les couches profondes sont spécifiques au domaine. C&#39;est pourquoi on peut <strong>réutiliser</strong> un CNN pré-entraîné sur une grande base d&#39;images et l&#39;adapter à une tâche spécifique (<em>transfer learning</em>).</p><h2 id="cnn-pour-la-segmentation" tabindex="-1">CNN pour la segmentation <a class="header-anchor" href="#cnn-pour-la-segmentation" aria-label="Permalink to &quot;CNN pour la segmentation&quot;">​</a></h2><p>Un CNN classique produit <strong>un vecteur de sortie</strong> (une classe par image). Pour la segmentation, on a besoin d&#39;<strong>un label par pixel</strong> — une sortie de la même taille que l&#39;entrée. C&#39;est le problème que résout l&#39;architecture <strong>U-Net</strong>, qui ajoute un décodeur symétrique au CNN encodeur.</p>`,22)])])}const g=n(o,[["render",r]]);export{h as __pageData,g as default};
